import { useState } from 'react';
import { PieChart, Pie, Cell, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

// ==========================================
// DUMMY DATA SECTION
// ==========================================
// In production, this data will come from your backend API
// Backend will provide ML-processed verdicts, not raw metrics

// KPI Metrics - Backend endpoint: GET /api/dashboard/kpis
const dummyKPIData = {
  totalSystems: { count: 847, delta: 12, trend: 'up' },
  healthySystems: { count: 623, delta: 8, trend: 'up' },
  warningSystems: { count: 189, delta: 15, trend: 'up' },
  criticalSystems: { count: 35, delta: -3, trend: 'down' },
  pendingApprovals: { count: 12, delta: 2, trend: 'up' }
};

// Risk Distribution for Donut Chart - Backend: GET /api/dashboard/risk-distribution
const dummyRiskDistribution = [
  { name: 'Healthy', value: 623, color: '#10b981' },
  { name: 'Warning', value: 189, color: '#f59e0b' },
  { name: 'Critical', value: 35, color: '#ef4444' }
];

// Health Score Trend - Backend: GET /api/dashboard/health-trend?range=7d
const dummyHealthTrend = [
  { date: 'Jan 12', score: 87.2 },
  { date: 'Jan 13', score: 86.8 },
  { date: 'Jan 14', score: 85.5 },
  { date: 'Jan 15', score: 84.9 },
  { date: 'Jan 16', score: 86.1 },
  { date: 'Jan 17', score: 87.3 },
  { date: 'Jan 18', score: 88.1 }
];

// Top Impacted Services - Backend: GET /api/dashboard/impacted-services
const dummyImpactedServices = [
  { name: 'Payment Gateway', impact: 'High', systems: 8 },
  { name: 'Customer Portal', impact: 'High', systems: 5 },
  { name: 'Inventory System', impact: 'Medium', systems: 12 },
  { name: 'Email Services', impact: 'Medium', systems: 6 },
  { name: 'Analytics Platform', impact: 'Low', systems: 4 }
];

// Critical Systems Table - Backend: GET /api/systems/critical
const dummyCriticalSystems = [
  {
    id: 'SYS-8472',
    owner: 'Finance Dept',
    healthScore: 23,
    rootCause: 'Hardware',
    confidence: 94,
    lastSeen: '2 min ago',
    status: 'critical'
  },
  {
    id: 'SYS-6291',
    owner: 'IT Operations',
    healthScore: 31,
    rootCause: 'Software',
    confidence: 89,
    lastSeen: '5 min ago',
    status: 'critical'
  },
  {
    id: 'SYS-4158',
    owner: 'Sales Dept',
    healthScore: 28,
    rootCause: 'Security',
    confidence: 92,
    lastSeen: '8 min ago',
    status: 'critical'
  },
  {
    id: 'SYS-9347',
    owner: 'HR Department',
    healthScore: 35,
    rootCause: 'Hardware',
    confidence: 87,
    lastSeen: '12 min ago',
    status: 'critical'
  },
  {
    id: 'SYS-2814',
    owner: 'Marketing',
    healthScore: 42,
    rootCause: 'Software',
    confidence: 91,
    lastSeen: '15 min ago',
    status: 'warning'
  }
];

// ==========================================
// MAIN ADMIN DASHBOARD COMPONENT
// ==========================================
function AdminDashboard({ userData, onLogout }) {
  const [selectedOrg, setSelectedOrg] = useState('global');
  const [timeRange, setTimeRange] = useState('7d');
  const [searchQuery, setSearchQuery] = useState('');
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [activeNav, setActiveNav] = useState('Dashboard');

  return (
    <div className="flex h-screen bg-gray-50">
      
      {/* LEFT SIDEBAR NAVIGATION */}
      <div className="w-64 bg-slate-800 text-white flex flex-col">
        {/* Logo Section */}
        <div className="p-6 border-b border-slate-700">
          <h1 className="text-xl font-bold">MaintenanceAI</h1>
          <p className="text-xs text-slate-400 mt-1">Intelligence Platform</p>
        </div>
        
        {/* Navigation Menu */}
        <nav className="flex-1 p-4">
          {[
            { name: 'Dashboard', icon: '📊' },
            { name: 'Systems', icon: '💻' },
            { name: 'Decisions', icon: '📋' },
            { name: 'Reports', icon: '📈' }
          ].map((item) => (
            <button
              key={item.name}
              onClick={() => setActiveNav(item.name)}
              className={`w-full flex items-center gap-3 px-4 py-3 mb-2 rounded-lg transition-all ${
                activeNav === item.name 
                  ? 'bg-blue-600 text-white' 
                  : 'text-slate-300 hover:bg-slate-700'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span className="font-medium">{item.name}</span>
            </button>
          ))}
        </nav>
      </div>

      {/* MAIN CONTENT AREA */}
      <div className="flex-1 flex flex-col overflow-hidden">
        
        {/* TOP APP BAR */}
        <header className="bg-white border-b border-gray-200 px-6 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              {/* Organization Selector */}
              <select
                value={selectedOrg}
                onChange={(e) => setSelectedOrg(e.target.value)}
                className="px-4 py-2 border border-gray-300 rounded-lg bg-gray-50 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="global">Global - All Organizations</option>
                <option value="na">North America</option>
                <option value="eu">Europe</option>
                <option value="apac">Asia Pacific</option>
              </select>

              {/* Time Range Selector */}
              <select
                value={timeRange}
                onChange={(e) => setTimeRange(e.target.value)}
                className="px-4 py-2 border border-gray-300 rounded-lg bg-gray-50 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="24h">Last 24 hours</option>
                <option value="7d">Last 7 days</option>
                <option value="30d">Last 30 days</option>
              </select>

              {/* Search Bar */}
              <div className="relative">
                <input
                  type="text"
                  placeholder="Search system ID or owner..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-80 px-4 py-2 pl-10 border border-gray-300 rounded-lg bg-gray-50 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
                <span className="absolute left-3 top-2.5 text-gray-400">🔍</span>
              </div>
            </div>

            <div className="flex items-center gap-4">
              {/* Notifications */}
              <button className="relative p-2 text-gray-600 hover:bg-gray-100 rounded-lg">
                <span className="text-xl">🔔</span>
                <span className="absolute top-0 right-0 w-5 h-5 bg-red-500 text-white text-xs rounded-full flex items-center justify-center">3</span>
              </button>

              {/* User Menu */}
              <div className="relative">
                <button
                  onClick={() => setShowUserMenu(!showUserMenu)}
                  className="w-10 h-10 bg-blue-600 text-white rounded-full flex items-center justify-center font-semibold hover:bg-blue-700 transition-colors"
                >
                  {userData?.email?.[0].toUpperCase() || 'A'}
                </button>
                {showUserMenu && (
                  <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-gray-200 py-2 z-50">
                    <div className="px-4 py-2 border-b border-gray-200">
                      <p className="text-sm font-semibold text-gray-800">{userData?.email || 'admin@example.com'}</p>
                      <p className="text-xs text-gray-500 capitalize">{userData?.role || 'Admin'}</p>
                    </div>
                    <button className="w-full px-4 py-2 text-left hover:bg-gray-100 text-sm text-gray-700">Profile</button>
                    <button className="w-full px-4 py-2 text-left hover:bg-gray-100 text-sm text-gray-700">Settings</button>
                    <button 
                      onClick={onLogout}
                      className="w-full px-4 py-2 text-left hover:bg-gray-100 text-red-600 text-sm font-medium"
                    >
                      Logout
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </header>

        {/* DASHBOARD CONTENT (SCROLLABLE) */}
        <main className="flex-1 overflow-y-auto p-6">
          
          {/* ROW 1: KPI CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-5 gap-4 mb-6">
            <KPICard
              title="Total Systems"
              count={dummyKPIData.totalSystems.count}
              delta={dummyKPIData.totalSystems.delta}
              trend={dummyKPIData.totalSystems.trend}
              icon="💻"
              color="blue"
            />
            <KPICard
              title="Healthy Systems"
              count={dummyKPIData.healthySystems.count}
              delta={dummyKPIData.healthySystems.delta}
              trend={dummyKPIData.healthySystems.trend}
              icon="✅"
              color="green"
            />
            <KPICard
              title="Warning Systems"
              count={dummyKPIData.warningSystems.count}
              delta={dummyKPIData.warningSystems.delta}
              trend={dummyKPIData.warningSystems.trend}
              icon="⚠️"
              color="yellow"
            />
            <KPICard
              title="Critical Systems"
              count={dummyKPIData.criticalSystems.count}
              delta={dummyKPIData.criticalSystems.delta}
              trend={dummyKPIData.criticalSystems.trend}
              icon="❌"
              color="red"
            />
            <KPICard
              title="Pending Approvals"
              count={dummyKPIData.pendingApprovals.count}
              delta={dummyKPIData.pendingApprovals.delta}
              trend={dummyKPIData.pendingApprovals.trend}
              icon="⏳"
              color="purple"
            />
          </div>

          {/* ROW 2: VISUAL INTELLIGENCE */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-6">
            
            {/* Risk Distribution Donut Chart */}
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-lg font-semibold mb-2">Risk Distribution</h3>
              <p className="text-sm text-gray-600 mb-4">Current system health breakdown</p>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={dummyRiskDistribution}
                      cx="50%"
                      cy="50%"
                      innerRadius={50}
                      outerRadius={80}
                      paddingAngle={5}
                      dataKey="value"
                    >
                      {dummyRiskDistribution.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={entry.color} />
                      ))}
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </div>
              <div className="flex justify-center gap-4 mt-4">
                {dummyRiskDistribution.map((item) => (
                  <div key={item.name} className="flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }}></div>
                    <span className="text-xs text-gray-600">{item.name}: {item.value}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Health Score Trend Line Chart */}
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-lg font-semibold mb-2">Average Health Score</h3>
              <p className="text-sm text-gray-600 mb-4">7-day trend (ML-calculated average)</p>
              <div className="h-64">
                <ResponsiveContainer width="100%" height="100%">
                  <LineChart data={dummyHealthTrend}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="date" tick={{ fontSize: 12 }} />
                    <YAxis domain={[80, 90]} tick={{ fontSize: 12 }} />
                    <Tooltip />
                    <Line 
                      type="monotone" 
                      dataKey="score" 
                      stroke="#3b82f6" 
                      strokeWidth={2}
                      dot={{ fill: '#3b82f6', r: 4 }}
                    />
                  </LineChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Top Impacted Business Services */}
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-lg font-semibold mb-2">Top Impacted Services</h3>
              <p className="text-sm text-gray-600 mb-4">Business services at risk</p>
              <div className="space-y-3">
                {dummyImpactedServices.map((service, index) => (
                  <div 
                    key={index} 
                    className="flex justify-between items-center p-3 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors"
                  >
                    <div>
                      <p className="font-semibold text-sm">{service.name}</p>
                      <p className="text-xs text-gray-500">{service.systems} systems affected</p>
                    </div>
                    <span className={`px-3 py-1 rounded-full text-xs font-semibold ${
                      service.impact === 'High' ? 'bg-red-100 text-red-700' :
                      service.impact === 'Medium' ? 'bg-yellow-100 text-yellow-700' :
                      'bg-blue-100 text-blue-700'
                    }`}>
                      {service.impact}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* ROW 3: CRITICAL SYSTEMS TABLE */}
          <div className="bg-white rounded-lg shadow">
            <div className="p-6 border-b border-gray-200">
              <div className="flex justify-between items-center">
                <div>
                  <h3 className="text-lg font-semibold">Critical Systems Requiring Attention</h3>
                  <p className="text-sm text-gray-600 mt-1">ML-identified systems with high-confidence issues</p>
                </div>
                <button className="px-4 py-2 border border-blue-600 text-blue-600 rounded-lg hover:bg-blue-50 font-medium text-sm">
                  View All Systems
                </button>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">System ID</th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Owner</th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Health Score</th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Primary Root Cause</th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Confidence</th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Last Seen</th>
                    <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {dummyCriticalSystems.map((system) => (
                    <tr key={system.id} className="hover:bg-gray-50">
                      <td className="px-6 py-4">
                        <span className="font-semibold text-blue-600">{system.id}</span>
                      </td>
                      <td className="px-6 py-4 text-sm text-gray-700">{system.owner}</td>
                      <td className="px-6 py-4">
                        <span className={`px-3 py-1 rounded-full text-xs font-semibold ${
                          system.healthScore < 30 ? 'bg-red-100 text-red-700' :
                          system.healthScore < 50 ? 'bg-yellow-100 text-yellow-700' :
                          'bg-green-100 text-green-700'
                        }`}>
                          {system.healthScore}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-3 py-1 rounded-full text-xs font-semibold border ${
                          system.rootCause === 'Hardware' ? 'border-blue-500 text-blue-700' :
                          system.rootCause === 'Software' ? 'border-purple-500 text-purple-700' :
                          'border-red-500 text-red-700'
                        }`}>
                          {system.rootCause}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <span className="text-sm font-semibold">{system.confidence}%</span>
                          <div className="w-16 h-2 bg-gray-200 rounded-full overflow-hidden">
                            <div 
                              className="h-full bg-green-500" 
                              style={{ width: `${system.confidence}%` }}
                            ></div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-xs text-gray-500">{system.lastSeen}</td>
                      <td className="px-6 py-4">
                        <div className="flex gap-2">
                          <button className="px-3 py-1 border border-gray-300 text-gray-700 rounded hover:bg-gray-50 text-sm">
                            Details
                          </button>
                          <button className="px-3 py-1 bg-blue-600 text-white rounded hover:bg-blue-700 text-sm">
                            Assign
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}

// KPI CARD COMPONENT
function KPICard({ title, count, delta, trend, icon, color }) {
  const colorClasses = {
    blue: 'bg-blue-50 text-blue-600',
    green: 'bg-green-50 text-green-600',
    yellow: 'bg-yellow-50 text-yellow-600',
    red: 'bg-red-50 text-red-600',
    purple: 'bg-purple-50 text-purple-600'
  };

  const trendColor = delta < 0 ? 'text-green-600' : 'text-red-600';

  return (
    <div className="bg-white rounded-lg shadow p-6 hover:shadow-lg transition-shadow cursor-pointer">
      <div className="flex justify-between items-start">
        <div>
          <p className="text-sm text-gray-600 mb-2">{title}</p>
          <p className="text-3xl font-bold mb-2">{count.toLocaleString()}</p>
          <div className="flex items-center gap-1">
            <span className={`text-sm font-semibold ${trendColor}`}>
              {trend === 'up' ? '↑' : '↓'} {Math.abs(delta)}
            </span>
            <span className="text-xs text-gray-500">
              {trend === 'up' ? 'increase' : 'decrease'}
            </span>
          </div>
        </div>
        <div className={`p-3 rounded-lg ${colorClasses[color]}`}>
          <span className="text-2xl">{icon}</span>
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
